// Price Planner
// v2.9 - charge window expansion biased toward earlier hours when neighbour prices
//         are within EARLY_BIAS_EUR of each other; keeps grid charging before solar peak
// v2.8 - solar forecast (energy_production_remaining_today) deducted from kwhNeeded;
//         grid charge window shrinks when solar will cover part of the charge
// v2.7 - discharge band filter raised to avgPrice (hours below avg can never be discharge hours)
// v2.6 - charge window centered on cheapest hour, expanded outward; price cap
//         replaced by contiguous window logic — lowest price sits in center of charge period
// v2.5 - dynamic CHARGE_ABS_RATIO/DISCHARGE_ABS_RATIO aligned with EMS v3.4
// v2.4 - avgPrice and currentPrice calculated from Frank Energie array, EnergyZero removed
// v2.3 - version defined as single variable at top
// v2.2 - SOC_NORMAL_THRESHOLD raised to 80%
// v2.1 - fixed msg.plannerVersion, DISCHARGE_ABS_MIN corrected
// v2.0 - dischargeThreshold recalculated after conflict filter

var PLANNER_VERSION      = 'v2.9';
var BATTERY_KWH          = 40;
var BATTERY_VOLTAGE      = 48;
var MAX_AMPS             = 200;
var ROUND_TRIP_EFF       = 0.85;
var SOC_MIN              = 10;
var SOC_MAX              = 95;
var SAFETY_BUFFER_H      = 1;
var SOC_NORMAL_THRESHOLD = 80;    // above this, use tight charge cap
var CHARGE_ABS_RATIO     = 0.55;  // tight cap = avg * this (mirrors EMS v3.4)
var DISCHARGE_ABS_RATIO  = 0.55;  // min discharge price = avg * this (mirrors EMS v3.4)
var SOLAR_FORECAST_EFF   = 0.90;  // how much of the solar forecast actually reaches the battery
var EARLY_BIAS_EUR       = 0.02;  // prefer earlier hour when price difference is within this margin

var maxChargeKw = (MAX_AMPS * BATTERY_VOLTAGE / 1000) * ROUND_TRIP_EFF;

var batterySoC = parseFloat(msg.batterySoC) || parseFloat(context.get('lastSoC')) || 50;
context.set('lastSoC', batterySoC);

// Solar forecast — kWh still expected today from Forecast.Solar integration
// Entity: sensor.energy_production_remaining_today (kWh)
// Falls back to 0 if sensor is unavailable so planner remains conservative
var solarForecastKwh = parseFloat(msg.solarForecastRemaining) || 0;
var solarUsableKwh   = solarForecastKwh * SOLAR_FORECAST_EFF;  // apply efficiency loss

var usableCapacity = BATTERY_KWH * ((SOC_MAX - SOC_MIN) / 100);
var currentKwh     = BATTERY_KWH * ((batterySoC - SOC_MIN) / 100);
var kwhNeeded      = Math.max(0, usableCapacity - currentKwh);
var kwhFromGrid    = Math.max(0, kwhNeeded - solarUsableKwh);  // solar covers part; grid covers rest
var hoursNeeded    = Math.ceil(kwhFromGrid / maxChargeKw) + SAFETY_BUFFER_H;

// Accept Frank Energie price array in either format
var prices = null;
if (Array.isArray(msg.frankPrices)) {
  prices = msg.frankPrices;
} else if (msg.frankPrices && Array.isArray(msg.frankPrices.prices)) {
  prices = msg.frankPrices.prices;
}

if (!prices || prices.length === 0) {
  msg.plannerVersion        = PLANNER_VERSION;
  msg.inChargingWindow      = null;
  msg.inDischargeWindow     = null;
  msg.dischargeThreshold    = null;
  msg.plannedChargeHours    = [];
  msg.plannedDischargeHours = [];
  msg.hoursNeeded           = hoursNeeded;
  msg.kwhNeeded             = parseFloat(kwhNeeded.toFixed(2));
  msg.kwhFromGrid           = parseFloat(kwhFromGrid.toFixed(2));
  msg.solarForecastKwh      = parseFloat(solarUsableKwh.toFixed(2));
  msg.cheapestPrice         = null;
  msg.plannerReason         = 'No price schedule available - using ratio fallback';
  node.status({ fill: 'yellow', shape: 'dot', text: PLANNER_VERSION + ' No price data - fallback mode' });
  return msg;
}

var now         = new Date();
var currentHour = now.getHours();

// Determine local date string for today's prices
var localOffset  = now.getTimezoneOffset() * 60000;
var localNow     = new Date(now.getTime() - localOffset);
var localDateStr = localNow.toISOString().substring(0, 10);

// Parse all prices and calculate avg + current from the array directly
var allParsed    = [];
var totalPrice   = 0;
var todayCount   = 0;
var currentPriceCalc = null;

for (var i = 0; i < prices.length; i++) {
  var p        = prices[i];
  var fromDate = new Date(p.from);
  var tillDate = new Date(p.till);
  var localHour = parseInt(p.from.substring(11, 13), 10);
  var dateStr   = p.from.substring(0, 10);
  allParsed.push({ from: fromDate, till: tillDate, price: parseFloat(p.price), localHour: localHour, dateStr: dateStr });

  if (dateStr === localDateStr) {
    totalPrice += parseFloat(p.price);
    todayCount++;
    if (localHour === currentHour) {
      currentPriceCalc = parseFloat(p.price);
    }
  }
}

var avgPriceCalc = todayCount > 0 ? totalPrice / todayCount : 0.10;

// Override msg so EMS uses Frank Energie prices
msg.currentPrice = currentPriceCalc !== null ? String(currentPriceCalc) : msg.currentPrice;
msg.avgPrice     = String(avgPriceCalc);

// Dynamic price caps based on today's average (mirrors EMS CFG ratios)
var chargePriceCap  = batterySoC >= SOC_NORMAL_THRESHOLD
  ? avgPriceCalc * CHARGE_ABS_RATIO      // tight: SoC healthy
  : avgPriceCalc * 0.99;                 // expanded: SoC low — any below-avg hour qualifies
var dischargeAbsMin = avgPriceCalc * DISCHARGE_ABS_RATIO;

// Only consider remaining hours today
var remainingToday = [];
for (var r = 0; r < allParsed.length; r++) {
  if (allParsed[r].dateStr === localDateStr && allParsed[r].till > now) {
    remainingToday.push(allParsed[r]);
  }
}

// Sort remaining by price ascending to find cheapest hour
var planPrices = remainingToday.slice();
planPrices.sort(function(a, b) { return a.price - b.price; });

var cheapestPrice = planPrices.length > 0 ? planPrices[0].price : null;

// Build charge window centered on the cheapest hour, expanding outward.
// remainingToday is already in time order (ascending from). Find the index
// of the cheapest hour within it, then expand left/right picking the
// cheaper neighbour at each step until hoursNeeded slots are filled.
// This guarantees the cheapest hour is always inside the window and the
// window is contiguous in time — the battery charges through the price valley.

var cheapestHour = planPrices.length > 0 ? planPrices[0].localHour : currentHour;

// Find center index in time-ordered remainingToday
var centerIdx = 0;
for (var ci = 0; ci < remainingToday.length; ci++) {
  if (remainingToday[ci].localHour === cheapestHour) { centerIdx = ci; break; }
}

var windowIndices = [centerIdx];
var left  = centerIdx - 1;
var right = centerIdx + 1;

while (windowIndices.length < hoursNeeded) {
  var canLeft  = left >= 0;
  var canRight = right < remainingToday.length;
  if (!canLeft && !canRight) break;

  var pickLeft;
  if      (!canRight) { pickLeft = true; }
  else if (!canLeft)  { pickLeft = false; }
  else {
    var leftPrice  = remainingToday[left].price;
    var rightPrice = remainingToday[right].price;
    var priceDiff  = rightPrice - leftPrice;  // positive = right is more expensive
    if (priceDiff >= -EARLY_BIAS_EUR) {
      // Right is more expensive, same price, or only marginally cheaper than left:
      // prefer left (earlier hour) — keeps grid charging before solar peak.
      // Only pick right when it is cheaper by more than the bias margin.
      pickLeft = true;
    } else {
      pickLeft = false;
    }
  }

  if (pickLeft) { windowIndices.push(left);  left--;  }
  else          { windowIndices.push(right); right++; }
}

var cheapestHours = [];
for (var wi = 0; wi < windowIndices.length; wi++) {
  cheapestHours.push(remainingToday[windowIndices[wi]].localHour);
}

var inWindow = cheapestHours.indexOf(currentHour) !== -1;

// Select discharge hours: expensive shoulder bands (morning + evening)
var morningBand = [];
var eveningBand = [];
for (var m = 0; m < remainingToday.length; m++) {
  var ph = remainingToday[m];
  // FIX: was dischargeAbsMin (avg*0.55) — any hour below avg should never be a discharge hour
  if (ph.price >= avgPriceCalc) {
    if (ph.localHour >= 6 && ph.localHour <= 11) {
      morningBand.push(ph);
    } else if (ph.localHour >= 16 && ph.localHour <= 23) {
      eveningBand.push(ph);
    }
  }
}

morningBand.sort(function(a, b) { return b.price - a.price; });
eveningBand.sort(function(a, b) { return b.price - a.price; });

var morningCount   = Math.ceil(morningBand.length * 0.50);
var eveningCount   = Math.ceil(eveningBand.length * 0.50);
var expensiveSlots = morningBand.slice(0, morningCount).concat(eveningBand.slice(0, eveningCount));

var expensiveHours = [];
for (var k = 0; k < expensiveSlots.length; k++) {
  expensiveHours.push(expensiveSlots[k].localHour);
}

// Initial discharge threshold from selected expensive slots
var dischargeThreshold = null;
if (expensiveSlots.length > 0) {
  var minExpPrice = expensiveSlots[0].price;
  for (var et = 1; et < expensiveSlots.length; et++) {
    if (expensiveSlots[et].price < minExpPrice) minExpPrice = expensiveSlots[et].price;
  }
  dischargeThreshold = minExpPrice;
}

// Remove discharge hours that conflict with charge hours
var filteredDischargeHours = [];
for (var fd = 0; fd < expensiveHours.length; fd++) {
  if (cheapestHours.indexOf(expensiveHours[fd]) === -1) {
    filteredDischargeHours.push(expensiveHours[fd]);
  }
}
expensiveHours = filteredDischargeHours;

// Recalculate threshold from the filtered set
dischargeThreshold = null;
for (var rt = 0; rt < remainingToday.length; rt++) {
  if (expensiveHours.indexOf(remainingToday[rt].localHour) !== -1) {
    if (dischargeThreshold === null || remainingToday[rt].price < dischargeThreshold) {
      dischargeThreshold = remainingToday[rt].price;
    }
  }
}

cheapestHours.sort(function(a, b) { return a - b; });
expensiveHours.sort(function(a, b) { return a - b; });

var inDischargeWindow = expensiveHours.indexOf(currentHour) !== -1;

msg.plannerVersion        = PLANNER_VERSION;
msg.inChargingWindow      = inWindow;
msg.inDischargeWindow     = inDischargeWindow;
msg.dischargeThreshold    = dischargeThreshold;
msg.plannedChargeHours    = cheapestHours;
msg.plannedDischargeHours = expensiveHours;
msg.hoursNeeded           = hoursNeeded;
msg.kwhNeeded             = parseFloat(kwhNeeded.toFixed(2));
msg.cheapestPrice         = cheapestPrice;
msg.plannerReason         =
  'Need ' + kwhNeeded.toFixed(1) + ' kWh total' +
    (solarUsableKwh > 0 ? ', solar covers ~' + solarUsableKwh.toFixed(1) + ' kWh, ' + kwhFromGrid.toFixed(1) + ' kWh from grid (' + hoursNeeded + 'h)' : ' from grid (' + hoursNeeded + 'h)') + '. ' +
  'SoC ' + batterySoC + '% - cheapest hour: ' + cheapestHour + 'h (' + (cheapestPrice !== null ? cheapestPrice.toFixed(3) : '?') + ' EUR), window centered there. ' +
  'Avg: ' + avgPriceCalc.toFixed(3) + ' EUR. ' +
  'Charge hours: ' + cheapestHours.map(function(h) { return h + 'h'; }).join(', ') +
  '. Discharge hours: ' + expensiveHours.map(function(h) { return h + 'h'; }).join(', ') +
  '. Discharge threshold: ' + (dischargeThreshold ? dischargeThreshold.toFixed(3) : '?') + ' EUR' +
  '. In charge window: ' + inWindow +
  '. In discharge window: ' + inDischargeWindow;

node.status({
  fill:  inWindow ? 'green' : inDischargeWindow ? 'red' : 'grey',
  shape: 'dot',
  text:  PLANNER_VERSION + ' ' + (inWindow ? 'CHG' : inDischargeWindow ? 'DCH' : 'IDLE') +
    ' | SoC:' + batterySoC + '% cap:' + chargePriceCap.toFixed(2) +
    ' | dch>' + (dischargeThreshold ? dischargeThreshold.toFixed(3) : '?') + 'EUR' +
    ' | hour ' + currentHour + 'h'
});

return msg;

// EMS Decision Engine
// v3.9 - canCharge: removed isNegPrice override on SOC_MAX; battery never charges above 95%
// v3.8 - SOC_CRITICAL branch now also requires price <= chargeAbsMax (avg × 0.55);
//         prevents emergency charging at above-average prices when avgPrice is skewed early morning
// v3.7 - isPriceLow: planner window can now be overridden by ratio threshold;
//         dramatically cheap hours (price <= CHARGE_THRESHOLD × avg) always charge
//         regardless of planned window, so cheap hours outside the window aren't wasted
// v3.6 - SOC_CRITICAL check changed < to <= (was missing boundary at exactly 20%);
//         isPriceHigh now also guards currentPrice >= avgPrice to prevent discharging below avg
// v3.5 - canDischarge bug fixed (|| SOC_MAX always true), discharge amp calc fixed (removed ROUND_TRIP_EFF from discharge path)
// v3.4 - all fixed price thresholds replaced with ratios of today's average
// v3.3 - solar surplus canChargeSolar flag, never blocked by price or SoC threshold
// v3.2 - solar surplus before discharge, SOC_DISCHARGE_MIN 15%, gross import target
// v3.1 - SOC_DISCHARGE_MIN 15%, SOC_CRITICAL 20%
// v3.0 - P1 phase readings used directly

var EMS_VERSION = 'EMS v3.9';

var CFG = {
  MAX_AMPS:             200,
  BATTERY_VOLTAGE:      48,
  BATTERY_KWH:          40,
  SOC_MIN:              10,
  SOC_MAX:              95,
  SOC_DISCHARGE_MIN:    15,
  SOC_CRITICAL:         20,
  CHARGE_THRESHOLD:     0.80,
  DISCHARGE_THRESHOLD:  1.20,
  CHARGE_ABS_RATIO:     0.55,
  DISCHARGE_ABS_RATIO:  0.55,
  DISCHARGE_OVERSHOOT:  1.25,
  EXPORT_BIAS_W:        800,
  HYSTERESIS:           0.05,
  SOLAR_SURPLUS_W:      500,
  SOLAR_SURPLUS_EXIT_W: 200,
  ROUND_TRIP_EFF:       0.85,
  GRID_MAX_A_PHASE:     18,
  GRID_VOLTAGE:         230,
  SAFETY_MARGIN_A:      2,
  MIN_DISCHARGE_A:      35
};

var currentPrice     = parseFloat(msg.currentPrice) || 0;
var avgPrice         = parseFloat(msg.avgPrice)     || 0.10;
var inChargingWindow = msg.inChargingWindow;

var gridImport       = parseFloat(msg.gridImport) || 0;
var gridExport       = parseFloat(msg.gridExport) || 0;
var netGridW         = (gridImport - gridExport) * 1000;
var dischargeTargetW = gridImport * 1000;

var phaseL1kW  = parseFloat(msg.phaseL1)   || 0;
var phaseL2kW  = parseFloat(msg.phaseL2)   || 0;
var phaseL3kW  = parseFloat(msg.phaseL3)   || 0;
var pac1       = parseFloat(msg.pac1)       || 0;
var pac2       = parseFloat(msg.pac2)       || 0;
var pac3       = parseFloat(msg.pac3)       || 0;
var batterySoC = parseFloat(msg.batterySoC) || 50;

var lastState    = context.get('lastState')    || 'idle';
var pendingState = context.get('pendingState') || 'idle';
var pendingCount = context.get('pendingCount') || 0;

var solarTotalW    = pac1 + pac2 + pac3;
var actualSurplusW = (netGridW < 0 && solarTotalW > 50 && Math.abs(netGridW) <= solarTotalW * 1.3) ? Math.abs(netGridW) : 0;

var priceRatio  = avgPrice > 0 ? currentPrice / avgPrice : 1;
var isNegPrice  = currentPrice < 0;

// Dynamic thresholds based on today's average — no fixed euro amounts
var chargeAbsMax    = avgPrice * CFG.CHARGE_ABS_RATIO;
var dischargeAbsMin = avgPrice * CFG.DISCHARGE_ABS_RATIO;

var chargeRatioThreshold    = lastState === 'charging'    ? CFG.CHARGE_THRESHOLD    + CFG.HYSTERESIS : CFG.CHARGE_THRESHOLD;
var dischargeRatioThreshold = lastState === 'discharging' ? CFG.DISCHARGE_THRESHOLD - CFG.HYSTERESIS : CFG.DISCHARGE_THRESHOLD;

var isPriceLow;
var isPriceVeryLow = priceRatio <= CFG.CHARGE_THRESHOLD && currentPrice <= chargeAbsMax;  // ratio override
if (batterySoC <= CFG.SOC_CRITICAL && currentPrice < avgPrice) {
  // Critical SoC — charge in any below-average hour regardless of window
  isPriceLow = true;
} else if (inChargingWindow === null) {
  // No planner data — use ratio fallback
  isPriceLow = isPriceVeryLow || isNegPrice;
} else {
  // Planner active — trust the window, but also charge if price is dramatically cheap
  // regardless of whether this hour was planned. Prevents wasting low-price hours
  // that fall outside the centered window (e.g. a cheap morning dip before 12h).
  isPriceLow = inChargingWindow || isPriceVeryLow || isNegPrice;
}

var isPriceHigh;
if (msg.inDischargeWindow === true) {
  // FIX: guard against planner flagging discharge hours below avg price
  isPriceHigh = currentPrice >= avgPrice && currentPrice >= dischargeAbsMin;
} else {
  isPriceHigh = priceRatio >= dischargeRatioThreshold && currentPrice >= dischargeAbsMin;
}

var canCharge      = batterySoC < CFG.SOC_MAX;  // FIX: removed isNegPrice override — never charge above SOC_MAX regardless of price
var canChargeSolar = batterySoC < CFG.SOC_MAX;
// FIX 1: was `(batterySoC > CFG.SOC_MIN || batterySoC > CFG.SOC_MAX) && ...`
//         `|| batterySoC > CFG.SOC_MAX` is almost never true and the || made the
//         first condition effectively ignored — now correctly just SOC_MIN guard.
var canDischarge   = batterySoC > CFG.SOC_MIN && batterySoC >= CFG.SOC_DISCHARGE_MIN;

var phaseL1A            = (phaseL1kW * 1000) / CFG.GRID_VOLTAGE;
var phaseL2A            = (phaseL2kW * 1000) / CFG.GRID_VOLTAGE;
var phaseL3A            = (phaseL3kW * 1000) / CFG.GRID_VOLTAGE;
var maxPhaseLoadA       = Math.max(phaseL1A, phaseL2A, phaseL3A);
var worstPhaseHeadroomA = Math.max(0, CFG.GRID_MAX_A_PHASE - maxPhaseLoadA - CFG.SAFETY_MARGIN_A);
var gridHeadroomW       = worstPhaseHeadroomA * CFG.GRID_VOLTAGE * 3;
var maxChargeFromGridA  = Math.round((gridHeadroomW / CFG.BATTERY_VOLTAGE) * CFG.ROUND_TRIP_EFF);
var maxAllowedChargeA   = Math.min(CFG.MAX_AMPS, maxChargeFromGridA);

var solarSurplusThreshold = lastState === 'charging' ? CFG.SOLAR_SURPLUS_EXIT_W : CFG.SOLAR_SURPLUS_W;

var CONFIRM_CYCLES = (isPriceLow || isPriceHigh || isNegPrice || (actualSurplusW > solarSurplusThreshold && canChargeSolar)) ? 1 : 2;

var charging    = false;
var discharging = false;
var targetAmps  = 0;
var reason      = '';

if (isNegPrice && canCharge) {
  charging   = true;
  targetAmps = maxAllowedChargeA;
  reason     = 'Negative price (' + currentPrice.toFixed(3) + ' EUR/kWh) - charging at ' + targetAmps + ' A (worst phase headroom: ' + worstPhaseHeadroomA.toFixed(1) + ' A)';

} else if (isPriceLow && canCharge) {
  var priceDiscount = 1 - priceRatio;
  var fraction      = 0.50 + (priceDiscount * 2.5);
  charging   = true;
  targetAmps = Math.round(Math.min(maxAllowedChargeA, maxAllowedChargeA * fraction));
  if (batterySoC < CFG.SOC_CRITICAL) {
    targetAmps = maxAllowedChargeA;
    reason     = 'Critical SoC (' + batterySoC + '%) - charging at max ' + targetAmps + ' A (price ' + currentPrice.toFixed(3) + ' EUR below avg ' + avgPrice.toFixed(3) + ' EUR)';
  } else if (inChargingWindow) {
    reason     = 'Planner: cheapest window (' + currentPrice.toFixed(3) + ' EUR) - charging at ' + targetAmps + ' A. Hours: ' + (msg.plannedChargeHours || []).join('h,') + 'h';
  } else {
    reason     = 'Price override: ' + Math.round(priceRatio * 100) + '% of avg (' + currentPrice.toFixed(3) + ' EUR) below threshold - charging at ' + targetAmps + ' A outside planned window';
  }

} else if (actualSurplusW > solarSurplusThreshold && canChargeSolar) {
  var surplusAmps = Math.round((actualSurplusW / CFG.BATTERY_VOLTAGE) / CFG.ROUND_TRIP_EFF);
  charging   = true;
  targetAmps = Math.min(CFG.MAX_AMPS, surplusAmps);
  reason     = 'Solar surplus ' + actualSurplusW.toFixed(0) + ' W (' + solarTotalW.toFixed(0) + ' W produced) - absorbing at ' + targetAmps + ' A';

} else if (isPriceHigh && canDischarge) {
  if (dischargeTargetW > 0) {
    var targetW = dischargeTargetW + CFG.EXPORT_BIAS_W;
    // FIX 2: removed / CFG.ROUND_TRIP_EFF — efficiency applies to charging only.
    //         discharge amps = DC watts needed ÷ DC bus voltage, then overshoot for lag.
    //         old formula inflated amps by factor of (OVERSHOOT / EFF) = 1.25/0.85 = ~1.47×
    //         new formula: (targetW / VOLTAGE) * OVERSHOOT only
    var neededAmps  = Math.round((targetW / CFG.BATTERY_VOLTAGE) * CFG.DISCHARGE_OVERSHOOT);
    var clampedAmps = Math.max(CFG.MIN_DISCHARGE_A, Math.min(CFG.MAX_AMPS, neededAmps));
    discharging = true;
    targetAmps  = clampedAmps;
    reason      = 'High price (' + (priceRatio * 100).toFixed(0) + '% of avg, ' + currentPrice.toFixed(3) + ' EUR) - discharging ' + targetAmps + ' A to cover ' + dischargeTargetW.toFixed(0) + ' W gross import + ' + CFG.EXPORT_BIAS_W + ' W export bias' + (neededAmps < CFG.MIN_DISCHARGE_A ? ' (raised to minimum ' + CFG.MIN_DISCHARGE_A + ' A)' : '');
  } else {
    discharging = true;
    targetAmps  = CFG.MIN_DISCHARGE_A;
    reason      = 'High price (' + (priceRatio * 100).toFixed(0) + '% of avg, ' + currentPrice.toFixed(3) + ' EUR) - exporting ' + CFG.MIN_DISCHARGE_A + ' A to grid at peak price (solar export: ' + actualSurplusW.toFixed(0) + ' W)';
  }

} else {
  reason = 'Idle - SoC ' + batterySoC + '%, price ' + currentPrice.toFixed(3) + ' EUR (' + (priceRatio * 100).toFixed(0) + '% of avg), solar ' + solarTotalW.toFixed(0) + ' W, netGrid ' + netGridW.toFixed(0) + ' W | ' + (msg.plannerReason || 'no planner');
}

if (charging && discharging) {
  discharging = false;
  reason += ' [conflict resolved: charge wins]';
}
if (targetAmps === 0) {
  charging    = false;
  discharging = false;
}

context.set('lastState', charging ? 'charging' : discharging ? 'discharging' : 'idle');

var rawState = charging ? 'charging' : discharging ? 'discharging' : 'idle';
var confirmedState;
if (rawState === pendingState) {
  var newCount = pendingCount + 1;
  context.set('pendingCount', newCount);
  if (newCount >= CONFIRM_CYCLES) {
    confirmedState = rawState;
    context.set('lastState', rawState);
  } else {
    confirmedState = lastState;
    reason += ' [confirming ' + newCount + '/' + CONFIRM_CYCLES + ']';
  }
} else {
  context.set('pendingState', rawState);
  context.set('pendingCount', 1);
  confirmedState = lastState;
  reason += ' [pending change to ' + rawState + ' 1/' + CONFIRM_CYCLES + ']';
}

charging    = confirmedState === 'charging';
discharging = confirmedState === 'discharging';
targetAmps  = (charging || discharging) ? targetAmps : 0;

if (targetAmps === 0) {
  charging    = false;
  discharging = false;
}

msg.payload = {
  version:     EMS_VERSION + ' / Planner ' + (msg.plannerVersion || 'unknown'),
  dc_amps:     targetAmps,
  charging:    charging,
  discharging: discharging,
  reason:      reason,
  planner: {
    inWindow:              msg.inChargingWindow,
    inDischargeWindow:     msg.inDischargeWindow,
    dischargeThreshold:    msg.dischargeThreshold || null,
    hoursNeeded:           msg.hoursNeeded,
    kwhNeeded:             msg.kwhNeeded,
    cheapestPrice:         msg.cheapestPrice,
    plannedHours:          msg.plannedChargeHours,
    plannedDischargeHours: msg.plannedDischargeHours,
    reason:                msg.plannerReason
  },
  inputs: {
    currentPrice:        currentPrice,
    avgPrice:            avgPrice,
    priceRatio:          parseFloat((priceRatio * 100).toFixed(1)),
    chargeAbsMax:        parseFloat(chargeAbsMax.toFixed(3)),
    dischargeAbsMin:     parseFloat(dischargeAbsMin.toFixed(3)),
    lastState:           lastState,
    batterySoC:          batterySoC,
    solarTotal_W:        solarTotalW,
    netGrid_W:           netGridW,
    dischargeTarget_W:   dischargeTargetW,
    actualSurplus_W:     actualSurplusW,
    phaseL1_A:           parseFloat(phaseL1A.toFixed(2)),
    phaseL2_A:           parseFloat(phaseL2A.toFixed(2)),
    phaseL3_A:           parseFloat(phaseL3A.toFixed(2)),
    maxPhaseLoad_A:      parseFloat(maxPhaseLoadA.toFixed(2)),
    worstHeadroom_A:     parseFloat(worstPhaseHeadroomA.toFixed(2)),
